import { EntityHelper } from 'src/utils/entity-helper';
import { Column, Entity, PrimaryGeneratedColumn, ManyToOne, JoinColumn } from 'typeorm';
import { Word } from 'src/word/entities/words.entity';

@Entity()
export class GameProgress extends EntityHelper {
  @PrimaryGeneratedColumn()
  id: number;

  @Column()
  userId: number;

  @ManyToOne(() => Word, (word) => word.gameProgresses)
  @JoinColumn({ name: 'wordId' })
  word: Word;

  @Column()
  wordId: number;

  @Column()
  known: boolean;

  @Column()
  createdAt: Date;
}
```

In the above code:

- `@ManyToOne(() => Word, (word) => word.gameProgresses)` specifies that `GameProgress` has a many-to-one relationship with `Word`.
- `@JoinColumn({ name: 'wordId' })` specifies that the relationship is based on the `wordId` property of `GameProgress`.
- `word: Word` creates a property on the `GameProgress` entity that represents the related `Word` entity.
- `wordId: number` is the foreign key to the `Word` entity.

By adding the relationship to the `GameProgress` entity, you can use the `GameProgress.word` property to access the associated `Word` entity's properties in your TypeORM queries.

