import { EntityHelper } from 'src/utils/entity-helper';
import { Entity, PrimaryGeneratedColumn, Column, OneToMany } from 'typeorm';
import { GameProgress } from 'src/game/entities/game.entity';

@Entity()
export class Word extends EntityHelper {
  @PrimaryGeneratedColumn()
  id: number;

  @Column()
  word: string;

  @Column()
  frequency: string;

  @Column('json')
  types: string[];

  @Column({ nullable: true })
  gender: string;

  @Column('json')
  translation_en: string[];

  @Column('json')
  example: { phrase: string; translation_en: string };

  @OneToMany(() => GameProgress, (gameProgress) => gameProgress.word)
  gameProgresses: GameProgress[];
}
```

In the above code:

- The `@OneToMany` decorator specifies that `Word` has a one-to-many relationship with `GameProgress`.
- The first parameter of `@OneToMany` specifies the `GameProgress` entity that will be related to `Word`.
- The second parameter of `@OneToMany` specifies the property on `GameProgress` that represents the relationship to `Word`.
- `gameProgresses: GameProgress[]` is a property of the `Word` entity that represents all the related `GameProgress` entities.

With this relationship defined, you can use the `Word.gameProgresses` property to access the associated `GameProgress` entities related to a particular `Word` entity.
